class Solution {
public:
    string lastSubstring(string s) {
        int maxIndex = 0, maxEnd = 0;
        for (int i = 1; i < s.size(); i++) {
            int j = maxEnd;
            while (j >= 0 && s[i] > s[j]) j--;
            if (i > j) {
                maxIndex = i;
                maxEnd = i;
            } else {
                maxEnd = i;
            }
        }
        return s.substr(maxIndex, s.size() - maxIndex);
    }
};
